// ─────────────────────────────────────────────────────────────────────────
// Regenerates functions/_lib/achievement.generated.mjs — a plain-ESM bundle
// of src/Achievement.jsx (react / react-dom / react-dom/server kept
// external) with Vite's `?raw` SVG imports resolved to inlined string
// literals.
//
// WHY THIS EXISTS (task-17): Achievement.jsx statically imports its 10
// vendored-furniture SVGs via Vite's `?raw` suffix (a plain build-time
// raw-text import, see that file's own header comment). Cloudflare Pages
// Functions' own bundler (wrangler's esbuild pass over ./functions) does
// NOT understand that suffix — confirmed directly: importing Achievement.jsx
// from a Pages Function fails with "No loader is configured for '.svg'
// files: …/royal.svg?raw" (see .superpowers/sdd/briefs/task-17-report.md).
// Rather than touch Achievement.jsx itself (Task 12's SSR seam is reused
// EXACTLY by the OG-image Function — not re-architected), this script
// resolves `?raw` ahead of time — the identical technique
// src/__tests__/helpers/bundleJSX.mjs already uses for the node --test SSR
// smoke test (same `rawSuffixPlugin`) — and writes a plain-JS bundle that
// Cloudflare's Functions bundler CAN understand natively (it's just ordinary
// ESM with string-literal SVG text baked in, no special syntax left).
//
// Run automatically via the pretest/build npm scripts (package.json) so the
// committed output can never silently drift from src/Achievement.jsx's real
// source. Also committed to git — like src/achievement-art/manifest.js — so
// a fresh checkout has a working functions/_lib/achievement.generated.mjs
// even before anyone runs `npm test`/`npm run build`.
//
// DO NOT hand-edit functions/_lib/achievement.generated.mjs — regenerate it
// with `node scripts/build-achievement-bundle.mjs`.
// ─────────────────────────────────────────────────────────────────────────

import * as esbuild from 'esbuild';
import { writeFile, readFile } from 'node:fs/promises';
import { pathToFileURL } from 'node:url';
import path from 'node:path';

const ROOT = path.resolve(import.meta.dirname, '..');
const ENTRY = path.join(ROOT, 'src/Achievement.jsx');
const OUT = path.join(ROOT, 'functions/_lib/achievement.generated.mjs');

// Kept external: resolved at the Function's own import site the normal way
// (Cloudflare's Functions bundler resolves plain npm-package imports from
// node_modules already — confirmed live with @resvg/resvg-wasm itself, see
// the report). This keeps the generated bundle small and means there is
// only ONE copy of react-dom/server in the final Worker.
const REACT_EXTERNALS = ['react', 'react-dom', 'react-dom/server', 'react/jsx-runtime', 'react/jsx-dev-runtime'];

// Same plugin as src/__tests__/helpers/bundleJSX.mjs's rawSuffixPlugin —
// resolves Vite's `?raw` suffix to the raw file text as the module's default
// export, exactly matching what Vite itself does for the real app build.
const rawSuffixPlugin = {
  name: 'vite-raw-suffix',
  setup(build) {
    build.onResolve({ filter: /\?raw$/ }, (args) => {
      const clean = args.path.replace(/\?raw$/, '');
      const base = args.resolveDir.endsWith('/') ? args.resolveDir : `${args.resolveDir}/`;
      const resolved = new URL(clean, pathToFileURL(base)).pathname;
      return { path: resolved, namespace: 'raw-ns' };
    });
    build.onLoad({ filter: /.*/, namespace: 'raw-ns' }, async (args) => {
      const text = await readFile(args.path, 'utf8');
      return { contents: `export default ${JSON.stringify(text)};`, loader: 'js' };
    });
  },
};

const HEADER = `// Generated by scripts/build-achievement-bundle.mjs from src/Achievement.jsx
// — DO NOT hand-edit. Regenerate with \`node scripts/build-achievement-bundle.mjs\`
// (also runs automatically via the "pretest"/"build" npm scripts).
// react / react-dom / react-dom/server / react/jsx-runtime stay EXTERNAL —
// resolved from node_modules at the importing Function's own bundle step.
// See that script's header comment for why this file exists at all.
`;

async function main() {
  const result = await esbuild.build({
    entryPoints: [ENTRY],
    bundle: true,
    format: 'esm',
    jsx: 'automatic',
    platform: 'node',
    write: false,
    external: REACT_EXTERNALS,
    plugins: [rawSuffixPlugin],
    logLevel: 'silent',
  });
  const code = HEADER + result.outputFiles[0].text;
  await writeFile(OUT, code, 'utf8');
  console.log(`wrote ${path.relative(ROOT, OUT)} (${code.length} bytes)`);
}

main().catch((err) => {
  console.error(err);
  process.exitCode = 1;
});
